func:
// Werte im Context speichern
if (msg.topic === "heizung_ein") flow.set("hk1_heizung", msg.payload);
else if (msg.topic === "aussentemp") flow.set("hk1_aussen", msg.payload);
else if (msg.topic === "frostschutz") flow.set("hk1_frost", msg.payload);
else if (msg.topic === "party_modus") flow.set("hk1_party", msg.payload);
else if (msg.topic === "timer") flow.set("hk1_timerActive", msg.payload);

var heizung = flow.get("hk1_heizung") === true || flow.get("hk1_heizung") === "true";
var aussen = Number(flow.get("hk1_aussen")) || 0;
var frost = Number(flow.get("hk1_frost")) || 3;
var party = flow.get("hk1_party") === true || flow.get("hk1_party") === "true";
var timerAktiv = flow.get("hk1_timerActive") === true || flow.get("hk1_timerActive") === "true";

if (party) timerAktiv = true;

// --- SOLLTEMPERATUR BERECHNEN ---
var solltemp = -aussen + 40;
if (solltemp > 70) solltemp = 70;
if (solltemp < 20) solltemp = 20;

// --- PUMPEN LOGIK & STATUS FARBEN ---
var statusText = "Warte auf Daten...";
var bgColor = "#95a5a6"; // Standard-Grau
var sommerbetrieb = (aussen >= 22);
var pumpeAn = false;

if (aussen < frost) {
    statusText = "❄️ Frostschutz (Pumpe EIN)";
    bgColor = "#3498db"; // Blau
    pumpeAn = true;
} else if (!heizung) {
    statusText = "❌ Hauptschalter AUS";
    bgColor = "#7f8c8d"; // Dunkelgrau
    pumpeAn = false;
} else if (sommerbetrieb) {
    statusText = "🏖️ Sommerbetrieb > 22°C";
    bgColor = "#f39c12"; // Orange
    solltemp = 20;
    pumpeAn = false;
} else if (timerAktiv && party) {
    statusText = "🔥 Dauer-Ein aktiv (Pumpe EIN)";
    bgColor = "#e74c3c"; // Rot
    pumpeAn = true;
} else if (timerAktiv) {
    statusText = "☀️ Tagbetrieb (Pumpe EIN)";
    bgColor = "#2ecc71"; // Grün
    pumpeAn = true;
} else {
    statusText = "🌙 Nachtabsenkung (Pumpe AUS)";
    bgColor = "#34495e"; // Nachtblau
    pumpeAn = false;
}

return [
    { payload: statusText, color: bgColor }, 
    { payload: solltemp },
    { payload: pumpeAn ? "AN" : "AUS", color: pumpeAn ? "#2ecc71" : "#e74c3c" }
];
